/**
 * Sync Task Dispatcher — PreToolUse Task Hook
 * Consolidates 3 Task PreToolUse hooks into a single dispatcher.
 *
 * Consolidated hooks (security-first order):
 * - unified-agent-safety-dispatcher (agent safety checks — FIRST)
 * - team-size-gate (limits team size — SECOND)
 * - task-existence-gate (task tracking enforcement — THIRD)
 *
 * SHORT-CIRCUIT: On first block, returns immediately without running remaining hooks.
 * Merges additionalContext from all passing hooks into a single output.
 *
 * CC 2.1.9 Compliant: Single PreToolUse dispatcher with merged additionalContext
 */

import type { HookInput, HookResult , HookContext} from '../../types.js';
import { outputSilentSuccess, extractContext } from '../../lib/common.js';

// Import consolidated hook implementations
import { unifiedAgentSafetyDispatcher } from './unified-agent-safety-dispatcher.js';
import { teamSizeGate } from './team-size-gate.js';
import { fableSpendConsent } from './fable-spend-consent.js';
import { taskExistenceGate } from './task-existence-gate.js';
import { taskAgentAdvisor } from './task-agent-advisor.js';
import { spawnIntentLogger } from './spawn-intent-logger.js';
import { toolInvocationLinter } from '../tool-invocation-linter.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'sync-task-dispatcher';

interface TaskHookConfig {
  name: string;
  fn: (input: HookInput, ctx: HookContext) => HookResult;
}

/**
 * Registry of Task PreToolUse hooks, executed in security-first order.
 * Agent safety dispatcher runs first to catch all safety violations.
 * Task existence gate runs last (advisory or blocking based on pipeline state).
 */
const TASK_HOOKS: TaskHookConfig[] = [
  { name: 'unified-agent-safety-dispatcher', fn: unifiedAgentSafetyDispatcher },
  { name: 'team-size-gate', fn: teamSizeGate },
  // fable-spend-consent: escalates explicit fable model pins to a user
  // permission prompt ($10/$50 per MTok is a deliberate spend decision).
  { name: 'fable-spend-consent', fn: fableSpendConsent },
  { name: 'task-existence-gate', fn: taskExistenceGate },
  // task-agent-advisor: suggests curated ork agents for ad-hoc names (#706).
  { name: 'task-agent-advisor', fn: taskAgentAdvisor },
  // spawn-intent-logger: records subagent_type + description to the spawn
  // log — PreToolUse is the only event that carries them (SubagentStart
  // payload has neither; live-verified CC 2.1.173). Append-only, never blocks.
  { name: 'spawn-intent-logger', fn: spawnIntentLogger },
  // tool-invocation-linter: registry-driven advisory for known-bad invocations
  // (e.g. Agent isolation:'worktree' — #1883). Runs LAST in the chain because
  // it's purely informational; never blocks at the warn/info severities.
  { name: 'tool-invocation-linter', fn: toolInvocationLinter },
];

/**
 * Consolidated sync Task PreToolUse dispatcher.
 *
 * Execution order:
 * 1. unified-agent-safety-dispatcher (can block — agent safety checks)
 * 2. team-size-gate (can block — team size limits)
 * 3. task-existence-gate (can block in pipeline — task tracking enforcement)
 *
 * On first block: SHORT-CIRCUIT immediately.
 * On pass: merge additionalContext from all hooks.
 */
export function syncTaskDispatcher(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const contextParts: string[] = [];

  for (const hook of TASK_HOOKS) {
    try {
      const result = hook.fn(input, ctx);

      if (!result.continue) {
        ctx.log(HOOK_NAME, `${hook.name} blocked — short-circuiting`);
        return result;
      }

      // Permission escalations (ask/deny) carry continue:true but must reach
      // CC verbatim — merging them into additionalContext would swallow the
      // prompt. Short-circuit and propagate (fable-spend-consent emits these).
      const decision = (result.hookSpecificOutput as { permissionDecision?: string } | undefined)
        ?.permissionDecision;
      if (decision === 'ask' || decision === 'deny') {
        ctx.log(HOOK_NAME, `${hook.name} escalated (${decision}) — short-circuiting`);
        return result;
      }

      const context = extractContext(result);
      if (context) {
        contextParts.push(context);
        ctx.log(HOOK_NAME, `${hook.name}: additionalContext collected`);
      }
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error);
      ctx.log(HOOK_NAME, `${hook.name} failed: ${msg}`, 'warn');
    }
  }

  if (contextParts.length === 0) {
    ctx.log(HOOK_NAME, 'All hooks silent');
    return outputSilentSuccess();
  }

  const mergedContext = contextParts.join('\n\n---\n\n');
  ctx.log(HOOK_NAME, `Merged ${contextParts.length} context(s)`);
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      additionalContext: mergedContext,
      hookEventName: 'PreToolUse',
    },
  };
}
